/* APL Environment styles */

#main-content {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-height: 0;
}

/* REPL panel */
.repl-panel {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
    outline: none;
}

.repl-panel:focus {
    outline: none;
}

.repl-output {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
    background: var(--base);
    font-family: var(--mono);
    font-size: 15px;
    line-height: 1.5;
    color: var(--green);
    white-space: pre;
}

.repl-line {
    min-height: 1.5em;
}

.repl-input-line {
    display: inline;
}

.repl-prompt {
    color: var(--blue);
}

.repl-input-text {
    color: var(--text);
}

.repl-cursor {
    color: var(--text);
    animation: none;
}

.repl-cursor-hidden {
    visibility: hidden;
}

