file.content:
/* P-Code VM Debugger panel styles */

.debugger {
    display: flex;
    flex-direction: column;
    flex: 1;
    overflow: hidden;
    min-height: 0;
}

/* Control bar */
.control-bar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 16px;
    border-bottom: 1px solid var(--surface1);
    background: var(--mantle);
    flex-shrink: 0;
}

.btn {
    font-family: var(--mono);
    font-size: 13px;
    padding: 4px 12px;
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
    background: var(--surface0);
    color: var(--text);
    transition: background 0.15s;
}

.btn:hover:not(:disabled) {
    background: var(--surface1);
}

.btn:disabled {
    opacity: 0.4;
    cursor: default;
}

.btn-reset {
    color: var(--red);
    border-color: var(--red);
}

.btn-step {
    color: var(--blue);
    border-color: var(--blue);
}

.btn-step-host {
    color: var(--overlay2);
    border-color: var(--overlay2);
}

.btn-run {
    color: var(--green);
    border-color: var(--green);
}

.btn-toggle {
    color: var(--overlay1);
    border-color: var(--overlay1);
    font-size: 11px;
    padding: 3px 8px;
}

.btn-toggle.active {
    color: var(--peach);
    border-color: var(--peach);
    background: var(--surface1);
}

.demo-select {
    font-family: var(--mono);
    font-size: 12px;
    padding: 3px 6px;
    background: var(--surface0);
    color: var(--text);
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
}

.status {
    font-size: 13px;
    font-weight: 600;
    margin-left: 8px;
    color: var(--yellow);
}

.pc-display {
    font-size: 13px;
    color: var(--blue);
    margin-left: auto;
}

