                    <HardwarePanel
                        led_on={self.led_on}
                        s2_on={self.s2_on}
                        last_tx={self.last_tx}
                        last_rx={self.last_rx}
                        {on_s2_toggle}
                    />
                </main>
                // Footer
                <footer>
                    <span>{"MIT License"}</span>
                    <span class="footer-sep">{"\u{00b7}"}</span>
